1053	\subsection{Ext-annihilation and depth-bound substrate}
1054	\label{subsec:ab_ext_depth_substrate}
1055	
1056	\begin{lemma}[Annihilator kills \(\text{Ext}\)]
1057	  \label{lem:ext_smul_eq_zero_of_mem_annihilator}
1058	  \lean{RingTheory.Module.ext_smul_eq_zero_of_mem_annihilator}
1059	  \uses{def:depth}
1060	  Let \(R\) be a commutative ring, let \(N, M\) be \(R\)-modules, fix \(i \in \mathbb N\),
1061	  and let \(e \in \text{Ext}^i_R(N, M)\). If \(x \in R\) annihilates \(N\) (i.e.\
1062	  \(x \in \text{Ann}_R(N)\)), then the \(R\)-action \(x \cdot e = 0\). Concretely,
1063	  \(x \cdot e = (\text{mk}_0(x \cdot \mathbf 1_N)) \circ e\), and \(x \cdot \mathbf 1_N = 0\)
1064	  since \(x\) annihilates \(N\).
1065	\end{lemma}
1066	\begin{proof}
1067	  Proved directly in Lean; this is the ``\(x \in \mathfrak m\) annihilates
1068	  \(\text{Ext}^*(\kappa, -)\)'' fragment underlying \cref{lem:depth_via_ext}.
1069	\end{proof}
1070	
1071	\begin{lemma}[\(\text{Ext}\)-vanishing below the depth]
1072	  \label{lem:ext_vanish_of_natCast_lt_depth}
1073	  \lean{RingTheory.Module.ext_vanish_of_natCast_lt_depth}
1074	  \uses{def:depth, lem:depth_via_ext}
1075	  Let \((R, \mathfrak m)\) be a Noetherian local ring with residue field \(\kappa\),
1076	  and let \(M\) be a nonzero finitely generated \(R\)-module. If
1077	  \((i : \mathbb N_\infty) < \text{depth}(M)\), then every element of
1078	  \(\text{Ext}^i_R(\kappa, M)\) is zero. This is the index-wise repackaging of
1079	  \cref{lem:depth_via_ext} convenient for the long-exact-sequence chases.
1080	\end{lemma}
1081	\begin{proof}
1082	  Proved directly in Lean, by instantiating \cref{lem:depth_via_ext} at
1083	  \(n = i + 1\).
1084	\end{proof}
1085	
1086	\begin{lemma}[\(\mathbb N_\infty\) successor bridge]
1087	  \label{lem:natCast_add_one_le_of_le_sub_one}
1088	  \lean{RingTheory.Module.natCast_add_one_le_of_le_sub_one}
1089	  For \(d \in \mathbb N_\infty\) and \(a \in \mathbb N\) with \(1 \leq a\): if
1090	  \((a : \mathbb N_\infty) \leq d - 1\) then \((a + 1 : \mathbb N_\infty) \leq d\). A
1091	  truncated-subtraction arithmetic lemma used for the \(\text{depth}(N') - 1\)
1092	  shift in the second inequality of \cref{lem:depth_short_exact_sequence}.
1093	\end{lemma}
1094	\begin{proof}
1095	  Proved directly in Lean, by case analysis on \(d = \top\) versus \(d\) finite.
1096	\end{proof}
1097	
1098	\begin{lemma}[Depth is a linear-equivalence invariant]
1099	  \label{lem:depth_eq_of_linearEquiv}
1100	  \lean{RingTheory.Module.depth_eq_of_linearEquiv}
1101	  \uses{def:depth}
1102	  Let \(R\) be a commutative ring, \(I \subseteq R\) an ideal, and \(M, M'\) two
1103	  \(R\)-modules related by an \(R\)-linear equivalence \(e : M \xrightarrow{\sim} M'\).
1104	  Then \(\text{depth}_I(M) = \text{depth}_I(M')\): both the side condition
1105	  \(I \cdot M = M\) and the regular-sequence supremum are preserved under \(e\).
1106	\end{lemma}
1107	\begin{proof}
1108	  Proved directly in Lean; this is the substrate that identifies
1109	  \(\text{depth}(M)\) with \(\text{depth}(R^k)\) for a finite free \(M\) in the
1110	  \(\text{pd}_R(M) = 0\) base case of \cref{thm:auslander_buchsbaum}.
1111	\end{proof}
1112	
1113	\subsection{Depth of a constant product module}
1114	\label{subsec:ab_depth_pi_substrate}
1115	
1116	\begin{lemma}[Ideal action on a constant product]
1117	  \label{lem:ideal_smul_top_pi_const}
1118	  \lean{RingTheory.Module.ideal_smul_top_pi_const}
1119	  For a commutative ring \(R\), an ideal \(I\), a finite index type \(\iota\), and an
1120	  \(R\)-module \(M\), the submodule \(I \cdot \top_{\iota \to M}\) equals the product
1121	  submodule \(\prod_{\iota} (I \cdot \top_M)\) of fibrewise ideal actions.
1122	\end{lemma}
1123	\begin{proof}
1124	  Proved directly in Lean, by mutual inclusion using the \(\text{Pi.single}\)
1125	  decomposition of an element of \(\iota \to M\).
1126	\end{proof}
1127	
1128	\begin{lemma}[Triviality of the ideal action on a constant product]
1129	  \label{lem:ideal_smul_top_pi_const_eq_top_iff}
1130	  \lean{RingTheory.Module.ideal_smul_top_pi_const_eq_top_iff}
1131	  \uses{lem:ideal_smul_top_pi_const}
1132	  For a nonempty finite index type \(\iota\): \(I \cdot \top_{\iota \to M} = \top\) if
1133	  and only if \(I \cdot \top_M = \top\). The forward direction reads off the fibre
1134	  witness from a \(\text{Pi.single}\) projection; the backward direction lifts a
1135	  fibre witness through \(\text{Pi.single}\).
1136	\end{lemma}
1137	\begin{proof}
1138	  Proved directly in Lean via \cref{lem:ideal_smul_top_pi_const}.
1139	\end{proof}
1140	
1141	\begin{definition}[Quotient of a constant product by a scalar]
1142	  \label{def:quotSMulTopPiConstLinearEquiv}
1143	  \lean{RingTheory.Module.quotSMulTopPiConstLinearEquiv}
1144	  \uses{lem:ideal_smul_top_pi_const}
1145	  For a commutative ring \(R\), a finite index type \(\iota\), a scalar \(r \in R\), and
1146	  an \(R\)-module \(M\), the canonical \(R\)-linear equivalence
1147	  \[
1148	    (\iota \to M)\big/ r \cdot \top \;\xrightarrow{\ \sim\ }\; \iota \to (M / r \cdot \top),
1149	  \]
1150	  obtained by rewriting \(r \cdot \top = \text{span}\{r\} \cdot \top\) and applying the
1151	  quotient-of-a-product identification.
1152	\end{definition}
1153	
1154	\begin{lemma}[Regularity on a constant product]
1155	  \label{lem:isRegular_pi_const_iff_of_nonempty}
1156	  \lean{RingTheory.Module.isRegular_pi_const_iff_of_nonempty}
1157	  \uses{def:quotSMulTopPiConstLinearEquiv}
1158	  For a nonempty finite index type \(\iota\) and a list \(rs\) of elements of \(R\), the
1159	  sequence \(rs\) is \((\iota \to M)\)-regular if and only if it is \(M\)-regular. The
1160	  proof inducts on \(rs\): the empty case reduces to
1161	  \(\text{Nontrivial}(\iota \to M) \leftrightarrow \text{Nontrivial}(M)\), and the cons
1162	  case combines pointwise \(\text{SMul}\)-regularity with
1163	  \cref{def:quotSMulTopPiConstLinearEquiv} to feed the inductive hypothesis.
1164	\end{lemma}
1165	\begin{proof}
1166	  Proved directly in Lean.
1167	\end{proof}
1168	
1169	\begin{lemma}[Depth of a constant product]
1170	  \label{lem:depth_pi_const_eq_depth_of_nonempty}
1171	  \lean{RingTheory.Module.depth_pi_const_eq_depth_of_nonempty}
1172	  \uses{def:depth, lem:ideal_smul_top_pi_const_eq_top_iff, lem:isRegular_pi_const_iff_of_nonempty}
1173	  For a commutative ring \(R\), an ideal \(I\), an \(R\)-module \(M\), and a nonempty
1174	  finite index type \(\iota\), one has \(\text{depth}_I(\iota \to M) = \text{depth}_I(M)\).
1175	  In particular a finite free module \(M \cong R^k\) has \(\text{depth}(M) = \text{depth}(R)\),
1176	  which closes the \(\text{pd}_R(M) = 0\) base case of \cref{thm:auslander_buchsbaum}.
1177	\end{lemma}
1178	\begin{proof}
1179	  Proved directly in Lean, combining
1180	  \cref{lem:ideal_smul_top_pi_const_eq_top_iff} (the side condition) with
1181	  \cref{lem:isRegular_pi_const_iff_of_nonempty} (the regular-sequence supremum).
1182	\end{proof}
