1184	\subsection{Surjection and projective-dimension substrate for the inductive step}
1185	\label{subsec:ab_surjection_substrate}
1186	
1187	\begin{lemma}[A regular element exists when depth is positive]
1188	  \label{lem:exists_isSMulRegular_of_one_le_depth}
1189	  \lean{RingTheory.Module.exists_isSMulRegular_of_one_le_depth}
1190	  \uses{def:depth}
1191	  For a Noetherian local ring \((R, \mathfrak m)\) and a nonzero finitely generated
1192	  \(R\)-module \(M\), if \(1 \leq \text{depth}(M)\) then there exists \(x \in \mathfrak m\)
1193	  that is \(M\)-regular. (Nakayama rules out the trivialisation
1194	  \(\mathfrak m \cdot M = M\), so the depth supremum exhibits a length-\(1\) witness.)
1195	\end{lemma}
1196	\begin{proof}
1197	  Proved directly in Lean.
1198	\end{proof}
