1200	\begin{lemma}[Kernel-SES depth inequalities for a finite free surjection]
1201	  \label{lem:depth_ses_ineqs_of_surjection_finite_localRing}
1202	  \lean{RingTheory.Module.depth_ses_ineqs_of_surjection_finite_localRing}
1203	  \uses{lem:depth_short_exact_sequence, lem:depth_pi_const_eq_depth_of_nonempty}
1204	  Let \(R\) be a Noetherian local ring, \(M\) a nonzero finite \(R\)-module, \(n \geq 1\),
1205	  and \(f : R^n \twoheadrightarrow M\) a surjection with \(\ker f\) nontrivial. Then
1206	  \[
1207	    \min\bigl(\text{depth}(R),\, \text{depth}(\ker f) - 1\bigr) \leq \text{depth}(M)
1208	    \quad\text{and}\quad
1209	    \min\bigl(\text{depth}(R),\, \text{depth}(M) + 1\bigr) \leq \text{depth}(\ker f).
1210	  \]
1211	  These are parts (2) and (3) of \cref{lem:depth_short_exact_sequence} for the SES
1212	  \(0 \to \ker f \to R^n \to M \to 0\), after identifying \(\text{depth}(R^n) = \text{depth}(R)\).
1213	\end{lemma}
1214	\begin{proof}
1215	  Proved directly in Lean; these are the two inequalities fed to
1216	  \cref{lem:enat_ab_inductive_combine} to close the inductive step of
1217	  \cref{lem:auslander_buchsbaum_formula_succ_pd}.
1218	\end{proof}
