1221	  \label{lem:exists_ne_zero_ext_of_depth_eq}
1222	  \lean{RingTheory.Module.exists_ne_zero_ext_of_depth_eq}
1223	  \uses{lem:depth_via_ext}
1224	  For a nonzero finite \(R\)-module \(M\) over a Noetherian local ring \((R, \mathfrak m)\)
1225	  with \(\text{depth}(M) = D\) finite, there is a nonzero element of
1226	  \(\text{Ext}^D_R(\kappa, M)\). (All \(\text{Ext}^i\) vanish for \(i < D\), and
1227	  vanishing fails at index \(D\).) This exhibits the nonzero class
1228	  \(\text{Ext}^{\text{depth}(R)}(\kappa, R^k) \neq 0\) in the base case of the formula.
1229	\end{lemma}
1230	\begin{proof}
